  Coq port of the row-level Schoenfield certificates from
  LeanProofs/A198683SchoenfieldRows.lean.

  The Count/Match rows below are generated from
  Oeis/A198683/sources/schoenfield-a198683.txt.  None
  represents a Count entry introducing a new class; Some j represents
  a Match entry pointing to the earlier 1-based row j.
*)

From Stdlib Require Import Arith.PeanoNat.
From Stdlib Require Import Bool.Bool.
From Stdlib Require Import Lists.List.
From Stdlib Require Import PArith.BinPos.
From LeanProofsCoq Require Import A198683Schoenfield.

Import ListNotations.
Set Implicit Arguments.
Open Scope nat_scope.
Set Warnings "-abstract-large-number".

Module LeanProofs.
Module A198683SchoenfieldRows.

Module AS := LeanProofsCoq.A198683Schoenfield.LeanProofs.A198683Schoenfield.

Inductive RowMap : Type :=
| Empty : RowMap
| Node : option nat -> RowMap -> RowMap -> RowMap.

Fixpoint lookupRow (key : positive) (m : RowMap) : option nat :=
  match key, m with
  | _, Empty => None
  | xH, Node value _ _ => value
  | xO key', Node _ l _ => lookupRow key' l
  | xI key', Node _ _ r => lookupRow key' r
  end.

Fixpoint insertRow (key : positive) (label : nat) (m : RowMap)
    : RowMap :=
  match key, m with
  | xH, Empty => Node (Some label) Empty Empty
  | xH, Node _ l r => Node (Some label) l r
  | xO key', Empty => Node None (insertRow key' label Empty) Empty
  | xO key', Node value l r => Node value (insertRow key' label l) r
  | xI key', Empty => Node None Empty (insertRow key' label Empty)
  | xI key', Node value l r => Node value l (insertRow key' label r)
  end.

Fixpoint labelsFromRowsFrom (rowKey : positive) (next : nat)
    (m : RowMap) (revLabels : list nat)
    (rows : list (option positive)) : option (list nat) :=
  match rows with
  | [] => Some (rev revLabels)
  | None :: rest =>
      labelsFromRowsFrom (Pos.succ rowKey) (S next)
        (insertRow rowKey next m) (next :: revLabels) rest
  | Some matchKey :: rest =>
      match lookupRow matchKey m with
      | Some label =>
          labelsFromRowsFrom (Pos.succ rowKey) next
            (insertRow rowKey label m) (label :: revLabels) rest
      | None => None
      end
  end.

Definition labelsFromRows (rows : list (option positive))
    : option (list nat) :=
  labelsFromRowsFrom 1%positive 1 Empty [] rows.

Definition rowCertificateOk (rows : list (option positive))
    (rowCount classes : nat) : bool :=
  match labelsFromRows rows with
  | Some labels => AS.certificateOk labels rowCount classes
  | None => false
  end.

